block0_hex = ""

data = bytes.fromhex(block0_hex)

# Split on null bytes — treat as null-delimited records
segments = data.split(b'\x00')

print("[*] Null-delimited segments:")
for i, seg in enumerate(segments):
    if len(seg) == 0:
        continue
    print(f"  [{i:3d}] len={len(seg):3d}  hex={seg.hex():<40s}", end="")
    # Flag segments of exactly 16 bytes — prime MD5 candidate
    if len(seg) == 16:
        print(f"  <== 16 BYTES (MD5 CANDIDATE!)", end="")
    # Try to decode as ASCII
    try:
        txt = seg.decode('ascii')
        print(f"  ascii='{txt}'", end="")
    except:
        pass
    print()

# Also try blocks 1 and 2 — read those too
print()
